noncompliant:
void function() {
    int x = 10;        // Noncompliant - x is never modified
    std::string name = "John"; // Noncompliant - name is never modified

    std::cout << x << std::endl;
    std::cout << name << std::endl;
}

compliant:
void function() {
    const int x = 10;        // Compliant - x is const
    const std::string name = "John"; // Compliant - name is const

    std::cout << x << std::endl;
    std::cout << name << std::endl;
}

void function2() {
    int x = 10;        // Compliant - x is modified
    x++;
    std::cout << x << std::endl;
}
